mapper.select:
select order_id, order_no, user_id, region_id, total_amount, pay_amount, status, payment_method, transaction_id, remark, admin_note, tracking_no, paid_at, shipped_at, completed_at, closed_at, expires_at, create_time, update_time from bh_order
and region_id = #{regionId}
and status = #{status}
order by order_id desc
